import Link from "next/link"
import { prisma } from "@/lib/prisma"
import {
  FREE_PLAN_DOG_LIMIT,
  getAccountPlanLabel,
  getChannelContentAccessLabel,
  getChannelContentCategoryLabel,
} from "@/lib/platform"
import { formatMoney, formatServiceMode } from "@/lib/community"
import AICoachPanel from "@/app/components/AICoachPanel"
import { getAuthSession } from "@/lib/auth"
import { getRoleLabel } from "@/lib/role"

export default async function Home() {
  const [session, dogs, trainings, users, blogPosts, channels, recentLessons, contentCount, threadCount] = await Promise.all([
    getAuthSession(),
    prisma.dog.count(),
    prisma.trainingSession.count(),
    prisma.user.count(),
    prisma.blogPost.findMany({
      where: { published: true },
      orderBy: [{ featured: "desc" }, { createdAt: "desc" }],
      take: 3,
      include: { author: true },
    }),
    prisma.forumChannel.findMany({
      where: { isPublic: true },
      include: {
        owner: { select: { name: true, headline: true } },
        contents: {
          where: { published: true },
          select: {
            id: true,
            slug: true,
            title: true,
            summary: true,
            category: true,
            accessLevel: true,
            durationMinutes: true,
            orderIndex: true,
          },
          orderBy: [{ orderIndex: "asc" }, { createdAt: "desc" }],
        },
        _count: { select: { subscriptions: true, threads: true } },
      },
      orderBy: [{ featured: "desc" }, { createdAt: "desc" }],
      take: 3,
    }),
    prisma.channelContent.findMany({
      where: { published: true },
      include: {
        channel: { select: { name: true, slug: true } },
      },
      orderBy: [{ orderIndex: "asc" }, { createdAt: "desc" }],
      take: 6,
    }),
    prisma.channelContent.count({ where: { published: true } }),
    prisma.forumThread.count(),
  ])
  const isLoggedIn = !!session?.user?.id
  const needsVerification = isLoggedIn && !session?.user?.emailVerifiedAt
  const primaryHref = needsVerification ? "/verify" : isLoggedIn ? "/dashboard" : "/courses"
  const primaryLabel = needsVerification ? "Confirmar meu email" : isLoggedIn ? "Voltar ao painel" : "Explorar cursos"
  const secondaryHref = isLoggedIn ? "/dogs" : "#coach-k9"
  const secondaryLabel = isLoggedIn ? "Ver meus caes" : "Testar a IA"

  return (
    <div className="min-h-[100svh] bg-[radial-gradient(circle_at_top,rgba(251,191,36,0.10),transparent_24%),radial-gradient(circle_at_80%_20%,rgba(34,211,238,0.12),transparent_28%),linear-gradient(160deg,#020617,#0f172a_52%,#111827)] text-white">
      <section className="relative overflow-hidden">
        <div className="pointer-events-none absolute inset-0">
          <div className="absolute -left-24 top-12 h-80 w-80 rounded-full bg-cyan-500/10 blur-3xl" />
          <div className="absolute right-0 top-0 h-[28rem] w-[28rem] rounded-full bg-amber-400/10 blur-3xl" />
          <div className="absolute bottom-10 left-1/3 h-56 w-56 rounded-full bg-emerald-500/8 blur-3xl" />
        </div>

        <div className="relative mx-auto grid min-h-[88svh] max-w-7xl gap-10 px-4 py-14 sm:px-6 xl:grid-cols-[1.05fr_0.95fr] xl:items-center">
          <div className="space-y-8">
            <div className="inline-flex items-center gap-2 rounded-full border border-amber-300/20 bg-amber-500/10 px-4 py-2 text-xs uppercase tracking-[0.28em] text-amber-100">
              Cursos, dicas e pratica
            </div>

            <div className="space-y-5">
              {isLoggedIn && (
                <div className="rounded-[26px] border border-emerald-300/20 bg-emerald-500/10 p-4 text-sm text-emerald-50">
                  <p className="text-xs uppercase tracking-[0.2em] text-emerald-100/80">Conta reconhecida</p>
                  <p className="mt-2">
                    {session.user?.name || session.user?.email}, seu perfil esta ativo como {getRoleLabel(session.user?.role)} no
                    plano {getAccountPlanLabel(session.user?.plan)}.
                  </p>
                  {needsVerification && (
                    <p className="mt-2 text-amber-100">Antes de continuar, confirme seu email para liberar a operacao completa.</p>
                  )}
                </div>
              )}
              <h1 className="max-w-4xl text-4xl font-bold leading-tight md:text-6xl">
                Uma plataforma para estudar melhor, praticar com clareza e voltar todo dia com vontade.
              </h1>
              <p className="max-w-2xl text-lg leading-8 text-slate-300">
                A K9 agora puxa o foco para o que mais move o usuario: trilhas de curso, dicas aplicaveis, rotina de
                treino e uma IA que ajuda a decidir o proximo passo com base no que ja existe na plataforma.
              </p>
            </div>

            <div className="flex flex-wrap gap-3">
              <Link
                href={primaryHref}
                className="rounded-2xl bg-[linear-gradient(135deg,#f59e0b,#fb7185)] px-6 py-4 text-sm font-semibold text-slate-950 shadow-xl shadow-amber-500/20 transition hover:-translate-y-0.5"
              >
                {primaryLabel}
              </Link>
              <Link
                href={secondaryHref}
                className="rounded-2xl border border-cyan-300/20 bg-cyan-500/10 px-6 py-4 text-sm font-medium text-cyan-100 transition hover:bg-cyan-500/20"
              >
                {secondaryLabel}
              </Link>

            </div>

            <div className="grid gap-4 md:grid-cols-3">
              <HeroChip title="Planos" value={`Free com ate ${FREE_PLAN_DOG_LIMIT} caes e acesso livre ao blog`} />
              <HeroChip title="Aprendizado vivo" value={`${contentCount} conteudos publicados e ${threadCount} conversas ativas`} />
              <HeroChip title="Apoio inteligente" value="IA para destravar duvidas e indicar o que estudar depois" />
            </div>
          </div>

          <div className="rounded-[36px] border border-white/10 bg-[linear-gradient(160deg,rgba(15,23,42,0.96),rgba(17,24,39,0.78)),radial-gradient(circle_at_top_right,rgba(245,158,11,0.16),transparent_30%)] p-6 shadow-2xl shadow-black/30">
            <div className="grid gap-4 md:grid-cols-2">
              <HeroStat label="Caes acompanhados" value={String(dogs)} detail="Cadastros vivos com saude, rotina e historico." />
              <HeroStat label="Treinos registrados" value={String(trainings)} detail="Pratica documentada com progresso e tarefas." />
              <HeroStat label="Contas ativas" value={String(users)} detail="Alunos e adestradores no mesmo ecossistema." />
              <HeroStat label="Posts abertos" value={String(blogPosts.length)} detail="Blog e eventos puxando a descoberta." />
            </div>

            <div className="mt-6 rounded-[30px] border border-white/10 bg-white/5 p-5">
              <div className="flex items-end justify-between gap-3">
                <div>
                  <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Agora na plataforma</p>
                  <h2 className="mt-2 text-2xl font-semibold">Estude assim que entrar</h2>
                </div>
                <Link href="/conteudos" className="text-sm text-cyan-300 hover:underline underline-offset-4">
                  Biblioteca
                </Link>
              </div>

              <div className="mt-4 space-y-3">
                {recentLessons.map((lesson) => (
                  <Link
                    key={lesson.id}
                    href={lesson.accessLevel === "FREE" ? `/conteudos/${lesson.slug}` : `/courses/${lesson.channel.slug}`}
                    className="block rounded-[22px] border border-white/10 bg-slate-950/35 p-4 transition hover:bg-white/10"
                  >
                    <div className="flex flex-wrap gap-2 text-xs">
                      <span className="rounded-full bg-amber-500/15 px-3 py-1 text-amber-100">
                        {getChannelContentCategoryLabel(lesson.category)}
                      </span>
                      <span className="rounded-full bg-white/10 px-3 py-1 text-gray-100">
                        {getChannelContentAccessLabel(lesson.accessLevel)}
                      </span>
                      {lesson.durationMinutes && (
                        <span className="rounded-full bg-white/10 px-3 py-1 text-gray-100">{lesson.durationMinutes} min</span>
                      )}
                    </div>
                    <h3 className="mt-3 text-lg font-semibold">{lesson.title}</h3>
                    <p className="mt-2 text-sm text-slate-300">{lesson.channel.name}</p>
                  </Link>
                ))}

                {recentLessons.length === 0 && (
                  <div className="rounded-[22px] border border-dashed border-white/15 bg-white/5 p-5 text-sm text-slate-300">
                    Os primeiros cursos serao exibidos aqui assim que forem publicados pelos adestradores.
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="mx-auto max-w-7xl px-4 pb-14 sm:px-6">
        <div className="grid gap-4 lg:grid-cols-3">
          <FeatureCard
            eyebrow="Cursos"
            title="Trilhas de treinos para seguir todo dia"
            description="Cada curso nasce dos canais e conteudos ja publicados. O usuario entra, enxerga as aulas e entende o que vem a seguir."
            href="/courses"
            cta="Abrir catalogo"
          />
          <FeatureCard
            eyebrow="Dicas"
            title="Conteudo curto para gerar acao rapida"
            description="Aulas, checklists, guias e posts curtos se misturam para facilitar consulta, revisao e pratica no dia a dia."
            href="/blog"
            cta="Ler dicas"
          />
          <FeatureCard
            eyebrow="IA"
            title="Assistente para acelerar decisao"
            description="A IA responde em portugues, contextualiza a duvida e aponta os conteudos mais proximos dentro da propria plataforma."
            href="#coach-k9"
            cta="Usar agora"
          />
        </div>
      </section>

      <section className="mx-auto max-w-7xl px-4 pb-14 sm:px-6">
        <div className="flex flex-col gap-4 md:flex-row md:items-end md:justify-between">
          <div>
            <p className="text-sm uppercase tracking-[0.2em] text-amber-200/80">Trilhas em destaque</p>
            <h2 className="mt-2 text-3xl font-semibold">Cursos com cara de acompanhamento continuo</h2>
            <p className="mt-3 max-w-3xl text-slate-300">
              O catalogo foi reorganizado para transformar canais e bibliotecas em trilhas claras de estudo.
            </p>
          </div>
          <Link
            href="/courses"
            className="rounded-2xl border border-white/15 px-5 py-3 text-sm text-gray-100 transition hover:bg-white/10"
          >
            Ver todos os cursos
          </Link>
        </div>

        <div className="mt-6 grid gap-4 xl:grid-cols-3">
          {channels.map((channel) => (
            <CourseSpotlightCard
              key={channel.id}
              href={`/courses/${channel.slug}`}
              title={channel.name}
              owner={channel.owner.name}
              description={channel.description}
              lessonCount={channel.contents.length}
              freeCount={channel.contents.filter((item) => item.accessLevel === "FREE").length}
              serviceMode={formatServiceMode(channel.serviceMode)}
              price={formatMoney(channel.subscriptionPrice) || "Entrada gratuita"}
              lessons={channel.contents.slice(0, 3).map((item) => item.title)}
            />
          ))}

          {channels.length === 0 && (
            <div className="rounded-[30px] border border-dashed border-white/15 bg-white/5 p-6 text-slate-300 xl:col-span-3">
              O catalogo vai ganhar vida assim que os primeiros canais publicarem trilhas de curso.
            </div>
          )}
        </div>
      </section>

      <section className="mx-auto max-w-7xl px-4 pb-14 sm:px-6">
        <div className="grid gap-4 xl:grid-cols-[1.1fr_0.9fr]">
          <div className="rounded-[32px] border border-white/10 bg-white/5 p-8 shadow-xl shadow-black/20">
            <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">O que estudar hoje</p>
            <h2 className="mt-2 text-3xl font-semibold">Dicas e leituras para manter o ritmo</h2>
            <div className="mt-6 grid gap-4 md:grid-cols-2">
              {blogPosts.map((post) => (
                <Link
                  key={post.id}
                  href={`/blog/${post.slug}`}
                  className="rounded-[24px] border border-white/10 bg-slate-950/30 p-5 transition hover:bg-white/10"
                >
                  <p className="text-xs uppercase tracking-[0.16em] text-cyan-200/80">{post.category}</p>
                  <h3 className="mt-3 text-xl font-semibold">{post.title}</h3>
                  <p className="mt-2 text-sm leading-6 text-slate-300">{truncate(post.excerpt || post.content, 145)}</p>
                  <p className="mt-4 text-xs text-slate-400">{post.author.name}</p>
                </Link>
              ))}

              {blogPosts.length === 0 && (
                <div className="rounded-[24px] border border-dashed border-white/15 bg-white/5 p-5 text-slate-300 md:col-span-2">
                  O blog ainda nao tem artigos publicados, mas a area ja esta pronta para receber dicas e eventos reais.
                </div>
              )}
            </div>
          </div>

          <div className="rounded-[32px] border border-white/10 bg-[linear-gradient(180deg,rgba(15,23,42,0.92),rgba(17,24,39,0.82))] p-8 shadow-xl shadow-black/20">
            <p className="text-sm uppercase tracking-[0.2em] text-amber-200/80">Metodo K9</p>
            <h2 className="mt-2 text-3xl font-semibold">Uma experiencia que convida o usuario a continuar</h2>
            <div className="mt-6 space-y-4">
              <MethodStep
                number="01"
                title="Descobrir"
                description="Ver cursos publicados, ler dicas livres e entender rapidamente o que faz sentido para o momento do cao."
              />
              <MethodStep
                number="02"
                title="Estudar"
                description="Seguir a trilha, consumir aulas curtas e voltar sempre para revisar sem se sentir perdido."
              />
              <MethodStep
                number="03"
                title="Praticar"
                description="Registrar treino, abrir agenda, acompanhar evolucao e transformar conteudo em rotina."
              />
              <MethodStep
                number="04"
                title="Perguntar"
                description="Acionar a IA para destravar uma duvida sem sair do contexto da propria plataforma."
              />
            </div>
          </div>
        </div>
      </section>

      <section className="mx-auto max-w-7xl px-4 pb-14 sm:px-6">
        <AICoachPanel
          eyebrow="Inteligencia aplicada"
          title="Sua proxima decisao de estudo pode sair daqui"
          description="Pergunte como montar rotina, que aula assistir primeiro ou como transformar uma duvida em plano de pratica. A IA responde e ainda aponta os conteudos mais proximos."
        />
      </section>

      <section id="planos" className="mx-auto max-w-7xl px-4 pb-20 sm:px-6">
        <div className="text-center">
          <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Planos</p>
          <h2 className="mt-2 text-3xl font-semibold">Entre com leveza e destrave mais quando fizer sentido</h2>
          <p className="mt-3 text-slate-300">O Free abre descoberta. Starter e Pro liberam a experiencia completa de estudo, comunidade e acompanhamento.</p>
        </div>

        <div className="mt-8 grid gap-4 lg:grid-cols-3">
          <PlanCard
            name="Free"
            price="R$ 0"
            description={`Ate ${FREE_PLAN_DOG_LIMIT} caes, blog, racas e descoberta inicial da plataforma.`}
            items={["Entrada sem atrito", "Cursos e dicas publicas", "Base do perfil e dos caes"]}
            href="/register"
            cta="Comecar no Free"
          />
          <PlanCard
            name="Starter"
            price="R$ 79/mes"
            description="Desbloqueia cursos de assinante, forum, treinos, calendario e canais com acompanhamento mais proximo."
            items={["Biblioteca completa", "Forum e canais", "Treinos e agenda", "Fluxo ideal para estudo continuo"]}
            href="/register"
            cta="Ativar Starter"
            highlight
          />
        </div>
      </section>
    </div>
  )
}

function HeroStat({ label, value, detail }: { label: string; value: string; detail: string }) {
  return (
    <div className="rounded-[24px] border border-white/10 bg-white/5 p-5">
      <p className="text-xs uppercase tracking-[0.2em] text-slate-400">{label}</p>
      <p className="mt-3 text-3xl font-semibold">{value}</p>
      <p className="mt-2 text-sm leading-6 text-slate-300">{detail}</p>
    </div>
  )
}

function HeroChip({ title, value }: { title: string; value: string }) {
  return (
    <div className="rounded-[24px] border border-white/10 bg-white/5 px-4 py-4">
      <p className="text-xs uppercase tracking-[0.2em] text-slate-400">{title}</p>
      <p className="mt-2 text-sm font-semibold leading-6 text-white">{value}</p>
    </div>
  )
}

function FeatureCard({
  eyebrow,
  title,
  description,
  href,
  cta,
}: {
  eyebrow: string
  title: string
  description: string
  href: string
  cta: string
}) {
  return (
    <Link
      href={href}
      className="rounded-[28px] border border-white/10 bg-white/5 p-6 shadow-lg shadow-black/20 transition hover:-translate-y-0.5 hover:bg-white/10"
    >
      <p className="text-xs uppercase tracking-[0.2em] text-cyan-200/80">{eyebrow}</p>
      <h3 className="mt-3 text-2xl font-semibold">{title}</h3>
      <p className="mt-3 text-sm leading-7 text-slate-300">{description}</p>
      <p className="mt-5 text-sm font-medium text-amber-200">{cta}</p>
    </Link>
  )
}

function CourseSpotlightCard({
  href,
  title,
  owner,
  description,
  lessonCount,
  freeCount,
  serviceMode,
  price,
  lessons,
}: {
  href: string
  title: string
  owner: string
  description: string
  lessonCount: number
  freeCount: number
  serviceMode: string
  price: string
  lessons: string[]
}) {
  return (
    <Link
      href={href}
      className="rounded-[30px] border border-white/10 bg-[linear-gradient(180deg,rgba(15,23,42,0.92),rgba(17,24,39,0.76))] p-6 shadow-lg shadow-black/25 transition hover:-translate-y-0.5 hover:bg-white/10"
    >
      <div className="flex flex-wrap gap-2 text-xs">
        <span className="rounded-full bg-amber-500/15 px-3 py-1 text-amber-100">{serviceMode}</span>
        <span className="rounded-full bg-white/10 px-3 py-1 text-gray-100">{price}</span>
        <span className="rounded-full bg-white/10 px-3 py-1 text-gray-100">{lessonCount} aulas</span>
      </div>
      <h3 className="mt-4 text-2xl font-semibold">{title}</h3>
      <p className="mt-2 text-sm text-slate-400">{owner}</p>
      <p className="mt-4 text-sm leading-7 text-slate-300">{truncate(description, 180)}</p>

      <div className="mt-5 rounded-[22px] border border-white/10 bg-white/5 p-4">
        <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Comece por aqui</p>
        <div className="mt-3 space-y-2">
          {lessons.slice(0, 3).map((lesson) => (
            <p key={lesson} className="text-sm text-slate-200">
              {lesson}
            </p>
          ))}
          {lessons.length === 0 && <p className="text-sm text-slate-300">As aulas aparecerao aqui assim que forem publicadas.</p>}
        </div>
      </div>

      <p className="mt-4 text-sm text-cyan-200">{freeCount} itens livres para descoberta</p>
    </Link>
  )
}

function MethodStep({ number, title, description }: { number: string; title: string; description: string }) {
  return (
    <div className="rounded-[24px] border border-white/10 bg-white/5 p-5">
      <div className="flex items-center gap-3">
        <span className="flex h-10 w-10 items-center justify-center rounded-2xl bg-amber-500/15 text-sm font-semibold text-amber-100">
          {number}
        </span>
        <h3 className="text-lg font-semibold">{title}</h3>
      </div>
      <p className="mt-3 text-sm leading-7 text-slate-300">{description}</p>
    </div>
  )
}

function PlanCard({
  name,
  price,
  description,
  items,
  href,
  cta,
  highlight = false,
}: {
  name: string
  price: string
  description: string
  items: string[]
  href: string
  cta: string
  highlight?: boolean
}) {
  return (
    <div
      className={`rounded-[30px] border p-6 shadow-xl shadow-black/20 ${
        highlight
          ? "border-amber-300/25 bg-[linear-gradient(160deg,rgba(245,158,11,0.18),rgba(15,23,42,0.94)_40%,rgba(17,24,39,0.84))]"
          : "border-white/10 bg-white/5"
      }`}
    >
      <p className="text-sm uppercase tracking-[0.18em] text-cyan-200/80">{name}</p>
      <p className="mt-4 text-4xl font-semibold">{price}</p>
      <p className="mt-4 text-sm leading-7 text-slate-300">{description}</p>

      <div className="mt-6 space-y-3">
        {items.map((item) => (
          <p key={item} className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-slate-100">
            {item}
          </p>
        ))}
      </div>

      <Link
        href={href}
        className={`mt-6 inline-flex rounded-2xl px-5 py-3 text-sm font-semibold transition hover:-translate-y-0.5 ${
          highlight
            ? "bg-[linear-gradient(135deg,#f59e0b,#fb7185)] text-slate-950 shadow-lg shadow-amber-500/20"
            : "border border-white/15 text-white hover:bg-white/10"
        }`}
      >
        {cta}
      </Link>
    </div>
  )
}

function truncate(value: string | null | undefined, max = 160) {
  if (!value) return ""
  return value.length > max ? `${value.slice(0, max).trim()}...` : value
}
